import UsuarioRepository from '../repositories/UsuarioRepository';
import { createHeadlessSupabaseClient } from '../utils/supabaseClient';
import {
  criarUsuarioDePerfil,
  parsePermissao,
  Permissao,
  type EntradaFormularioUsuario,
  type PerfilDb,
  type Usuario,
} from '../classes';

function normalizeRole(role: unknown): string {
  return parsePermissao(String(role || ''));
}

function mergeProfileWithUsersRow(profile: PerfilDb | null, usersRow: Record<string, unknown> | null): Usuario {
  if (!usersRow) return criarUsuarioDePerfil(profile as PerfilDb);
  if (!profile) return criarUsuarioDePerfil(profileFromUsersRowOnly(usersRow));
  const rProfile = normalizeRole(profile?.role || profile?.permissao);
  const rUsers = normalizeRole(usersRow.role);
  const role =
    rProfile === Permissao.ADM || rUsers === Permissao.ADM
      ? Permissao.ADM
      : rProfile || String(usersRow.role || Permissao.Aluno);
  const name =
    (profile?.name && String(profile.name).trim()) ||
    (profile?.nome && String(profile.nome).trim()) ||
    (usersRow.full_name && String(usersRow.full_name).trim()) ||
    (usersRow.name && String(usersRow.name).trim()) ||
    '';
  return criarUsuarioDePerfil({
    ...profile,
    id: profile?.id || String(usersRow.id),
    email: profile?.email || String(usersRow.email || ''),
    name,
    role,
    created_at: profile?.created_at || (usersRow.created_at as string | undefined),
    updated_at: profile?.updated_at || (usersRow.updated_at as string | undefined),
  });
}

function profileFromUsersRowOnly(usersRow: Record<string, unknown>): PerfilDb {
  const role = normalizeRole(usersRow.role);
  const email = String(usersRow.email || '');
  return {
    id: String(usersRow.id),
    email,
    name: String(usersRow.full_name || usersRow.name || '').trim() || email.split('@')[0] || '',
    role,
    created_at: usersRow.created_at as string | undefined,
    updated_at: usersRow.updated_at as string | undefined,
  };
}

function formularioParaPerfilDb(
  userData: EntradaFormularioUsuario,
  id?: string,
): Partial<PerfilDb> & { role: string } {
  const permissao = parsePermissao(String(userData.permissao));
  const base: Partial<PerfilDb> & { role: string } = {
    name: (userData.nome || '').trim(),
    email: userData.email,
    role: permissao,
    matricula: userData.matricula ?? undefined,
    curso: userData.curso,
    formacao: userData.formacao,
    codigo: userData.codigo ?? undefined,
    telefone: userData.telefone,
    data_nascimento: userData.dataNascimento,
  };
  if (id) base.id = id;
  return base;
}

const UsuarioService = {
  async PesquisaUsuario() {
    const rows = await UsuarioRepository.PesquisaUsuario();
    return rows.map((row) => criarUsuarioDePerfil(row as PerfilDb));
  },

  async PesquisaUsuarioPorId(id: string) {
    const row = await UsuarioRepository.PesquisaUsuarioPorId(id);
    return criarUsuarioDePerfil(row as PerfilDb);
  },

  async CadastroUsuario(userData: EntradaFormularioUsuario) {
    const { email, senha, nome, permissao } = userData;
    const role = parsePermissao(String(permissao));

    const signupClient = createHeadlessSupabaseClient();
    const { data: authData, error } = await signupClient.auth.signUp({
      email,
      password: senha || '',
      options: {
        data: {
          name: (nome || '').trim(),
          role,
        },
      },
    });
    if (error) throw error;
    if (!authData?.user?.id) {
      throw new Error('Não foi possível criar o utilizador na autenticação.');
    }

    let profile = await UsuarioRepository.PesquisaUsuarioPorIdOpcional(authData.user.id);
    if (profile) return criarUsuarioDePerfil(profile as PerfilDb);

    const novo = await UsuarioRepository.CadastroUsuario({
      ...formularioParaPerfilDb(userData, authData.user.id),
      created_at: new Date().toISOString(),
    });
    return criarUsuarioDePerfil(novo as PerfilDb);
  },

  async AtualizarUsuario(id: string, userData: Partial<EntradaFormularioUsuario>) {
    const payload = formularioParaPerfilDb({
      nome: userData.nome || '',
      email: userData.email || '',
      permissao: userData.permissao || Permissao.Aluno,
      matricula: userData.matricula,
      curso: userData.curso,
      formacao: userData.formacao,
      codigo: userData.codigo,
      telefone: userData.telefone,
      dataNascimento: userData.dataNascimento,
    });
    const allowed = ['name', 'role', 'email', 'matricula', 'curso', 'formacao', 'codigo', 'telefone', 'data_nascimento'];
    const filtered = Object.fromEntries(
      Object.entries(payload).filter(([k]) => allowed.includes(k)),
    );
    const updated = await UsuarioRepository.AtualizarUsuario(id, filtered);
    return criarUsuarioDePerfil(updated as PerfilDb);
  },

  async DeletarUsuario(id: string) {
    return await UsuarioRepository.DeletarUsuario(id);
  },

  async PesquisaPerfilUsuario(userId: string) {
    const profile = await UsuarioRepository.PesquisaUsuarioPorIdOpcional(userId);
    let usersRow: Record<string, unknown> | null = null;
    try {
      usersRow = await UsuarioRepository.PesquisaRegistroUsersOpcional(userId);
    } catch {
      usersRow = null;
    }
    if (!profile && !usersRow) {
      const row = await UsuarioRepository.PesquisaUsuarioPorId(userId);
      return criarUsuarioDePerfil(row as PerfilDb);
    }
    if (!profile) {
      return criarUsuarioDePerfil(profileFromUsersRowOnly(usersRow as Record<string, unknown>));
    }
    return mergeProfileWithUsersRow(profile as PerfilDb, usersRow);
  },
};

export default UsuarioService;
